export type Season = "26S" | "26W"

/** 路線・便数計画の 1 行。 */
export interface RoutePlan {
  id: string
  /** 路線（OD）。例: HND–ITM */
  origin: string
  destination: string
  /** 表示用の路線ラベル */
  pair: string
  /** 計画便数（往復/日） */
  freq: number
  /** 前ダイヤ比 */
  freqDelta: number
  /** 主力機材 */
  fleet: string
  /** 1 便あたり提供座席 */
  seats: number
  /** 平均搭乗率 L/F (0–100) */
  loadFactor: number
  /** 就航率 (0–100) */
  completion: number
  /** 損益分岐搭乗率 B/E L/F (0–100) */
  breakeven: number
  /** 計画ステータス */
  status: "確定" | "増便" | "減便" | "新規" | "運休検討"
  season: Season
  /** コードシェア相手（任意） */
  codeshare?: string
}

