/** 発着スロット — 1 時間帯あたりの占有便（空港別）。congestion を計算するために実数で持つ。 */
export interface SlotOccupant {
  hour: number // 6..21
  /** 出発便数 */
  dep: number
  /** 到着便数 */
  arr: number
}

/** 空港のスロット定義 + 1時間あたり処理上限。 */
