"use client"

import * as React from "react"
import {
  Badge,
  Gantt,
  type GanttItem,
  type GanttItemTone,
  type GanttRow,
} from "@gunjo/ui"

import { rotationDay, rotations, type TailRotation } from "./data"

const KIND_TONE: Record<string, GanttItemTone> = {
  便: "info",
  折返し: "muted",
  整備: "warning",
}

/**
 * 機材ローテーション（テール × 時刻）。Gantt の 1 item = 1 テールの 1 日、その
 * segments[] に 便→折返し→便→整備 を入れる（コンポーネントが想定する用途そのもの）。
 * 注意: Gantt の時間軸は「日カラム」基準。日内（時単位）を見せるため startDate/endDate を
 * 当日の時間帯に寄せ、dayWidth を広げて 1 日カラムを横長にしている。
 */
export function FleetRotation({
  onSelectTail,
}: {
  onSelectTail?: (tail: string) => void
}) {
  const rows: GanttRow[] = rotations.map((r: TailRotation) => ({
    id: r.tail,
    label: r.tail,
    sublabel: `${r.fleet} ・ ${r.base}`,
  }))

  const items: GanttItem[] = rotations.map((r) => {
    const first = r.segments[0]
    const last = r.segments[r.segments.length - 1]
    const hasInfeasible = r.segments.some((s) => s.feasible === false)
    return {
      id: `rot-${r.tail}`,
      rowId: r.tail,
      start: first.start,
      end: last.end,
      label: r.tail,
      tone: hasInfeasible ? "destructive" : "info",
      ariaLabel: `${r.tail} ローテーション${hasInfeasible ? " 機材繰り不整合あり" : ""}`,
      segments: r.segments.map((s) => ({
        start: s.start,
        end: s.end,
        kind: s.kind,
        label: s.label,
        tone:
          s.feasible === false ? "destructive" : KIND_TONE[s.kind] ?? "default",
      })),
    }
  })

  // 当日 06:00 → 翌 12:00（HNL 深夜便の翌朝着まで包含）。
  const startDate = `${rotationDay}T06:00`
  const endDate = `2026-07-16T12:00`

  return (
    <div className="flex flex-col gap-3">
      <div className="flex flex-wrap items-center gap-2">
        <span className="text-sm font-semibold">機材アサイン / ローテーション</span>
        <Badge variant="secondary">{rotationDay}</Badge>
        <Badge variant="info">便</Badge>
        <Badge variant="warning">整備</Badge>
        <Badge variant="destructive">折返しMCT不足</Badge>
      </div>
      <Gantt
        rows={rows}
        items={items}
        startDate={startDate}
        endDate={endDate}
        dayWidth={520}
        laneHeight={30}
        rowLabelWidth={132}
        label="機材ローテーション ガントチャート"
        onSelectItem={(item) =>
          onSelectTail?.(item.rowId)
        }
      />
      <p className="text-xs text-muted-foreground">
        バーをクリックでテールを選択。折返しが赤＝最小地上時間(MCT)不足で機材繰り不整合。
      </p>
    </div>
  )
}

"use client"

import * as React from "react"
import {
  Badge,
  DataTable,
  Delta,
  Meter,
  type ColumnDef,
} from "@gunjo/ui"

import type { RoutePlan } from "./data"

const STATUS_VARIANT: Record<
  RoutePlan["status"],
  "default" | "secondary" | "success" | "warning" | "destructive" | "info" | "outline"
> = {
  確定: "secondary",
  増便: "success",
  減便: "warning",
  新規: "info",
  運休検討: "destructive",
}

/**
 * 路線・便数計画テーブル。DataTable（tanstack ColumnDef）の cell レンダラに
 * @gunjo/ui の Badge / Delta / Meter を埋め込んで密度の高い行を作る。
 * cell が関数なので "use client" 必須。
 */
export function RouteTable({
  data,
  onSelectRoute,
  selectedId,
}: {
  data: RoutePlan[]
  onSelectRoute: (route: RoutePlan) => void
  selectedId?: string
}) {
  const columns = React.useMemo<ColumnDef<RoutePlan, unknown>[]>(
    () => [
      {
        accessorKey: "pair",
        header: "路線",
        cell: ({ row }) => (
          <div className="flex flex-col">
            <span className="font-semibold tabular-nums">{row.original.pair}</span>
            {row.original.codeshare ? (
              <span className="text-[11px] text-muted-foreground">
                コードシェア {row.original.codeshare}
              </span>
            ) : null}
          </div>
        ),
      },
      {
        accessorKey: "freq",
        header: "便数/日",
        cell: ({ row }) => (
          <div className="flex items-center gap-1.5 tabular-nums">
            <span className="font-medium">{row.original.freq}</span>
            {row.original.freqDelta !== 0 ? (
              <Delta value={row.original.freqDelta} />
            ) : (
              <span className="text-xs text-muted-foreground">±0</span>
            )}
          </div>
        ),
      },
      {
        accessorKey: "fleet",
        header: "機材",
        cell: ({ row }) => (
          <span className="whitespace-nowrap text-sm">{row.original.fleet}</span>
        ),
      },
      {
        accessorKey: "seats",
        header: "提供座席",
        cell: ({ row }) => (
          <span className="tabular-nums">{row.original.seats}</span>
        ),
      },
      {
        accessorKey: "loadFactor",
        header: "搭乗率 L/F",
        cell: ({ row }) => (
          <div className="min-w-[120px]">
            <Meter
              size="inline"
              value={row.original.loadFactor}
              max={100}
              unit="%"
              direction="higher-is-better"
              target={row.original.breakeven}
              label={`${row.original.pair} 搭乗率`}
            />
          </div>
        ),
      },
      {
        accessorKey: "completion",
        header: "就航率",
        cell: ({ row }) => (
          <span className="tabular-nums">{row.original.completion.toFixed(1)}%</span>
        ),
      },
      {
        accessorKey: "breakeven",
        header: "B/E L/F",
        cell: ({ row }) => (
          <span className="tabular-nums text-muted-foreground">
            {row.original.breakeven}%
          </span>
        ),
      },
      {
        accessorKey: "status",
        header: "区分",
        cell: ({ row }) => (
          <Badge variant={STATUS_VARIANT[row.original.status]}>
            {row.original.status}
          </Badge>
        ),
      },
    ],
    []
  )

  return (
    <DataTable<RoutePlan, unknown>
      columns={columns}
      data={data}
      pageSize={10}
      onRowClick={onSelectRoute}
      getRowState={(row) => (row.id === selectedId ? "selected" : undefined)}
      filter={{ columnId: "pair", placeholder: "路線で絞り込み（例: HND）…" }}
      labels={{
        filterPlaceholder: "路線で絞り込み…",
        noResults: "該当する路線がありません",
        rowsPerPage: "表示件数",
        paginationSummary: (from, to, total) => `${from}–${to} / 全${total}路線`,
        pageSummary: (cur, totalPages) => `${cur} / ${totalPages}ページ`,
        previous: "前へ",
        next: "次へ",
        firstPage: "最初のページ",
        lastPage: "最後のページ",
      }}
    />
  )
}

"use client"

import * as React from "react"
import {
  Badge,
  Meter,
  ScheduleGrid,
  type ScheduleAxisItem,
  type ScheduleCell,
} from "@gunjo/ui"

import type { AirportSlots } from "./data"

/**
 * 発着スロットグリッド。時間帯（06–21時）を列、出発/到着/合計を行にした
 * リソース×時刻のマトリクス。ScheduleGrid を流用し、合計セルに Meter(inline) を
 * 入れて枠使用率を可視化。上限超過の時間帯は destructive トーン（conflict ring）。
 */
export function SlotGrid({
  airport,
  pendingHour,
}: {
  airport: AirportSlots
  /** 「新規枠を試す」プレビュー対象の時間帯（+1便を incoming で重ねる） */
  pendingHour?: number
}) {
  const columns: ScheduleAxisItem[] = airport.occupancy.map((o) => ({
    id: `h${o.hour}`,
    label: `${o.hour}`,
    sublabel: "時",
    ariaLabel: `${o.hour}時台`,
  }))

  const rows: ScheduleAxisItem[] = [
    { id: "dep", label: "出発", sublabel: "STD" },
    { id: "arr", label: "到着", sublabel: "STA" },
    { id: "total", label: "合計", sublabel: `枠 ${airport.hourlyCap}/h` },
  ]

  const cells: ScheduleCell[] = []
  for (const o of airport.occupancy) {
    const total = o.dep + o.arr
    const incoming = pendingHour === o.hour ? 1 : 0
    const projected = total + incoming
    const over = projected > airport.hourlyCap
    const near = !over && projected >= airport.hourlyCap

    cells.push({
      rowId: "dep",
      colId: `h${o.hour}`,
      content: <span className="tabular-nums text-sm">{o.dep}</span>,
      ariaLabel: `${o.hour}時台 出発 ${o.dep}便`,
    })
    cells.push({
      rowId: "arr",
      colId: `h${o.hour}`,
      content: <span className="tabular-nums text-sm">{o.arr}</span>,
      ariaLabel: `${o.hour}時台 到着 ${o.arr}便`,
    })
    cells.push({
      rowId: "total",
      colId: `h${o.hour}`,
      tone: over ? "destructive" : near ? "warning" : "default",
      description: over
        ? `${o.hour}時台 発着合計 ${projected}便 上限${airport.hourlyCap}超過`
        : `${o.hour}時台 発着合計 ${projected}便 / 上限${airport.hourlyCap}`,
      content: (
        <div className="flex flex-col gap-1">
          <Meter
            size="inline"
            value={total}
            incoming={incoming || undefined}
            max={airport.hourlyCap}
            showValue={false}
            label={`${o.hour}時台 発着枠使用`}
          />
          <span
            className={
              "text-[11px] font-semibold tabular-nums " +
              (over ? "text-destructive" : near ? "text-warning" : "text-muted-foreground")
            }
          >
            {projected}/{airport.hourlyCap}
            {incoming ? "＋1" : ""}
          </span>
        </div>
      ),
    })
  }

  return (
    <div className="flex flex-col gap-3">
      <div className="flex flex-wrap items-center gap-2">
        <span className="text-sm font-semibold">
          {airport.name}（{airport.code}）発着枠
        </span>
        {airport.constrained ? (
          <Badge variant="warning">発着枠制約あり</Badge>
        ) : (
          <Badge variant="secondary">制約なし</Badge>
        )}
        <span className="text-xs text-muted-foreground">
          上限 {airport.hourlyCap} 発着/時 ・ 06:00–21:00
        </span>
      </div>
      <ScheduleGrid
        rows={rows}
        columns={columns}
        cells={cells}
        label={`${airport.name} 発着スロットグリッド`}
        cornerLabel="時刻"
        minColumnWidth={56}
        rowHeaderWidth={84}
      />
      <div className="flex flex-wrap items-center gap-x-4 gap-y-1 text-xs text-muted-foreground">
        <LegendDot className="bg-card border border-border" label="余裕" />
        <LegendDot className="bg-warning-subtle border border-warning-border" label="満枠近接" />
        <LegendDot className="bg-destructive-subtle border border-destructive-border" label="上限超過" />
        <span>＋1 = 新規枠プレビュー</span>
      </div>
    </div>
  )
}

function LegendDot({ className, label }: { className: string; label: string }) {
  return (
    <span className="inline-flex items-center gap-1.5">
      <span className={"inline-block size-3 rounded-sm " + className} aria-hidden="true" />
      {label}
    </span>
  )
}
